// Example REST API request using JavaScript fetch
// GET request to retrieve user data
fetch('https://api.example.com/api/v1/users/123', {
  method: 'GET',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer your-auth-token-here'
  }
})
.then(response => {
  if (response.ok) {
    return response.json();
  }
  throw new Error('Network response was not ok');
})
.then(data => {
  console.log('User data:', data);
})
.catch(error => {
  console.error('Error fetching user:', error);
});

// POST request to create a new user
fetch('https://api.example.com/api/v1/users', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer your-auth-token-here'
  },
  body: JSON.stringify({
    username: 'ahmed_said',
    email: 'ahmed@example.com',
    password: 'securePassword123'
  })
})
.then(response => response.json())
.then(data => {
  console.log('User created:', data);
})
.catch(error => {
  console.error('Error creating user:', error);
});

# Example Nginx configuration for serving a web application
# This configuration handles both static files and proxies to backend

server {
    listen 80;
    server_name www.example.com example.com;

    # Redirect HTTP to HTTPS
    return 301 https://$server_name$request_uri;
}

server {
    listen 443 ssl http2;
    server_name www.example.com example.com;

    # SSL configuration
    ssl_certificate /etc/ssl/certs/example.crt;
    ssl_certificate_key /etc/ssl/private/example.key;
    ssl_protocols TLSv1.2 TLSv1.3;

    # Root directory for static files
    root /var/www/mysite;
    index index.html index.htm;

    # Serve static files directly
    location ~* \.(jpg|jpeg|png|gif|css|js|ico|svg)$ {
        expires 30d;
        add_header Cache-Control "public, immutable";
    }

    # Proxy dynamic requests to backend application
    location /api/ {
        proxy_pass http://127.0.0.1:3000;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host $host;
        proxy_cache_bypass $http_upgrade;
    }

    # Custom error pages
    error_page 404 /404.html;
    error_page 500 502 503 504 /50x.html;

    # Access and error logs
    access_log /var/log/nginx/mysite_access.log;
    error_log /var/log/nginx/mysite_error.log;
}

# Example Controller class in Python (simplified)
class ProfileController:
    def __init__(self, user_model, session):
        self.user_model = user_model
        self.session = session

    def show(self, request):
        """Handle GET request to view user profile"""
        # Check if user is logged in
        user_id = self.session.get('user_id')
        if not user_id:
            return self.redirect('/login')

        # Get user data from Model
        user = self.user_model.get_user_by_id(user_id)
        if not user:
            return self.error_404("User not found")

        # Get user's recent posts
        posts = self.user_model.get_user_posts(user_id, limit=5)

        # Check if current user can edit this profile
        can_edit = (user_id == user['id']) or self.user_model.is_admin(user_id)

        # Prepare data for View
        view_data = {
            'username': user['username'],
            'email': user['email'],
            'registration_date': user['created_at'],
            'posts': posts,
            'can_edit': can_edit,
            'is_admin': self.user_model.is_admin(user_id)
        }

        # Render View with data and return response
        return self.render('profile.html', view_data)

    def update(self, request):
        """Handle POST request to update user profile"""
        user_id = self.session.get('user_id')
        if not user_id:
            return self.redirect('/login')

        # Get form data from request
        new_username = request.form.get('username')
        new_email = request.form.get('email')

        # Validate and update through Model
        try:
            self.user_model.update_user(user_id, new_username, new_email)
            self.session.set_flash('Profile updated successfully', 'success')
        except ValueError as e:
            self.session.set_flash(str(e), 'error')

        # Redirect back to profile page
        return self.redirect('/profile')
